create table dirkspzm32.isi_avis_pack (
    lieferanten_nr          varchar2(9 char) not null enable,
    slb_nr                  varchar2(8 char) not null enable,
    lieferschein_nr         varchar2(8 char) not null enable,
    lieferschein_pos        number(*, 5) not null enable,
    lte_name                varchar2(22 char),
    lhm_name                varchar2(50 char),
    packmittel_nr_lieferant varchar2(22 char) not null enable,
    anz_packmittel          number(*, 0) not null enable,
    fuellmenge              number(*, 3),
    lte_id                  varchar2(20 char) not null enable,
    lhm_id                  varchar2(20 char) not null enable,
    verpackung_abmessung    number(*, 3),
    stapelfaktor            number(*, 0),
    label_kennung           varchar2(1 char),
    verpackung_kennung      varchar2(1 char),
    eigentum_kennung        varchar2(1 char),
    einlager_status         varchar2(1 char) default 'N' not null enable,
    einlager_datum          date
);

alter table dirkspzm32.isi_avis_pack
    add constraint pk_isi_avis_pack
        primary key ( lieferanten_nr,
                      slb_nr,
                      lieferschein_nr,
                      lieferschein_pos,
                      packmittel_nr_lieferant,
                      lte_id,
                      lhm_id )
            using index enable;


